import sys
from typing import List

class Solution:
    def factorial(self, n: int) -> List[int]:
        memo = {0: 1, 1: 1}
        def calc(n: int) -> int:
            if n not in memo: memo[n] = n * calc(n - 1)
            return memo[n]
        res = []
        for i in range(n, 0, -1):
            res.append(calc(i))
        return res

if __name__ == '__main__':
    n = int(sys.stdin.readline())
    print(*Solution().factorial(n))

