#include <iostream>
#include <vector>
using namespace std;

class Solution
{
public:
    vector<int> factorial(int n)
    {
        vector<int> result(n);
        result[0] = 1;
        for (int i = 1; i < n; i++)
        {
            result[i] = i * result[i - 1];
        }
        return result;
    }
};

int main()
{
    int n;
    cin >> n;
    Solution s;
    for (int i = 0; i < n; i++)
    {
        cout << s.factorial(n)[i] << ' '; 
    }
    return 0;
}
